<template>
  <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12">
  <div :class="{'row': true,'total_disable_class_bg':isDisabled(question)}" id="alldiv"> 
    <div
      v-for="(question, index) in securityQuestions"
      :key="index"
      class="col-sm-12 col-md-6 col-lg-6 col-xl-4 setMails"
    >
      <div class="form-group">
        <div class="input-group">
          <input
            type="text"
            v-model="question.value"
            class="form-control Secret questadded"
            maxlength="100"
            :class="{ total_disable_class: isDisabled(question) }"
          />

          <div class="input-group-append">
            <span class="input-group-text border-0 bg-transparent p-0 pl-2">

                <a
                  class="round-icon-small btn-danger-light"
                  href="javascript:;"
                  @click="removeQuestion(question, index)"
                >
                  <i class="fa fa-trash"></i>
                </a>

                <a
                  class="round-icon-small btn-success-light"
                  href="javascript:;"
                  @click="saveQuestion(question)"
                >
                  <i class="fa fa-floppy-o"></i>
                </a>

                <a
                  v-if="isLast(index)"
                  class="round-icon-small btn-dark"
                  href="javascript:;"
                  @click="addMore"
                >
                  <i class="fa fa-plus"></i>
                </a>
            

            </span>
          </div>
        </div>
      </div>
    </div>
  </div>
  </div>
</template>

<script>
export default {
  name: "SecurityQuestions",

  props: {
    securityQuestions: {
      type: Array,
      required: true
    },
    isEnabled: {
      type: Boolean,
      default: true
    }
  },

  methods: {
    isDisabled(question) {
      debugger;
      return !this.isEnabled;
    },

    isLast(index) {
      return index === this.securityQuestions.length - 1;
    },

    saveQuestion(question) {
      this.$emit("save", question);
    },

    removeQuestion(question, index) {
      this.$emit("remove", { question, index });
    },

    addMore() {
      this.$emit("add-more");
    }
  }
};
</script>
